"use client"

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { TrendingUp, Users, DollarSign, BarChart3 } from "lucide-react"
import Link from "next/link"

interface Fund {
  id: string
  fund_name: string
  fund_code: string
  fund_type: string
  nav: number
  aum: number
  expense_ratio: number
  risk_level: string
  inception_date: string
  fund_performance?: Array<{
    period: string
    returns: number
    sharpe_ratio: number
  }>
}

interface ManagedFundsListProps {
  funds: Fund[]
}

export function ManagedFundsList({ funds }: ManagedFundsListProps) {
  const formatCurrency = (value: number) => {
    const crores = value / 10000000
    return `₹${crores.toFixed(2)} Cr`
  }

  const getOneYearReturn = (fund: Fund) => {
    const oneYearPerf = fund.fund_performance?.find((p) => p.period === "1Y")
    return oneYearPerf?.returns || 0
  }

  return (
    <div className="space-y-6">
      {funds.length > 0 ? (
        funds.map((fund) => {
          const oneYearReturn = getOneYearReturn(fund)

          return (
            <Card key={fund.id}>
              <CardHeader>
                <div className="flex items-start justify-between">
                  <div>
                    <CardTitle className="text-xl">{fund.fund_name}</CardTitle>
                    <p className="mt-1 text-sm text-gray-500">{fund.fund_code}</p>
                  </div>
                  <div className="flex gap-2">
                    <Badge variant="outline">{fund.fund_type}</Badge>
                    <Badge
                      className={
                        fund.risk_level === "high"
                          ? "bg-red-100 text-red-800"
                          : fund.risk_level === "medium"
                            ? "bg-yellow-100 text-yellow-800"
                            : "bg-green-100 text-green-800"
                      }
                    >
                      {fund.risk_level} risk
                    </Badge>
                  </div>
                </div>
              </CardHeader>
              <CardContent>
                <div className="grid gap-4 md:grid-cols-4">
                  <div className="flex items-center gap-3 rounded-lg border p-4">
                    <div className="rounded-full bg-blue-100 p-2">
                      <DollarSign className="h-5 w-5 text-blue-600" />
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Current NAV</p>
                      <p className="text-lg font-semibold">₹{Number(fund.nav).toFixed(2)}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3 rounded-lg border p-4">
                    <div className="rounded-full bg-green-100 p-2">
                      <Users className="h-5 w-5 text-green-600" />
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">AUM</p>
                      <p className="text-lg font-semibold">{formatCurrency(Number(fund.aum))}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3 rounded-lg border p-4">
                    <div className="rounded-full bg-purple-100 p-2">
                      <TrendingUp className="h-5 w-5 text-purple-600" />
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">1Y Return</p>
                      <p className={`text-lg font-semibold ${oneYearReturn >= 0 ? "text-green-600" : "text-red-600"}`}>
                        {oneYearReturn >= 0 ? "+" : ""}
                        {oneYearReturn.toFixed(2)}%
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3 rounded-lg border p-4">
                    <div className="rounded-full bg-orange-100 p-2">
                      <BarChart3 className="h-5 w-5 text-orange-600" />
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Expense Ratio</p>
                      <p className="text-lg font-semibold">{Number(fund.expense_ratio).toFixed(2)}%</p>
                    </div>
                  </div>
                </div>
                <div className="mt-4 flex gap-2">
                  <Link href={`/manager/funds/${fund.id}`} className="flex-1">
                    <Button className="w-full">View Details</Button>
                  </Link>
                  <Link href={`/manager/funds/${fund.id}/holdings`}>
                    <Button variant="outline">Manage Holdings</Button>
                  </Link>
                  <Link href={`/manager/funds/${fund.id}/trades`}>
                    <Button variant="outline">Execute Trade</Button>
                  </Link>
                </div>
              </CardContent>
            </Card>
          )
        })
      ) : (
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-gray-500">No funds assigned to you yet.</p>
            <p className="mt-2 text-sm text-gray-400">Contact an administrator to get fund assignments.</p>
          </CardContent>
        </Card>
      )}
    </div>
  )
}
